"""Tests for steer-phase token span tracking."""

from __future__ import annotations

from branching_eval.branch_executor import _append_steer_phase_span
from branching_eval.runtime_types import DecodeOutcome, PathState
from branching_eval.tree_runtime_utils import leaf_event_payload, leaf_from_outcome


def test_leaf_from_outcome_preserves_steer_phase_token_spans() -> None:
    """Leaf rows should carry response-token spans generated by steer requests."""

    state = PathState(
        node_id="node_root",
        assistant_prefix="<think>",
        prompt_token_ids=(1, 2),
        token_ids=(),
        token_traces=(),
        branch_points_used=0,
    )
    outcome = DecodeOutcome(
        event_type="terminated",
        trigger_type=None,
        assistant_prefix="<think><steer>Plan</steer></think>",
        prompt_token_ids=(1, 2, 3, 4, 5),
        token_ids=(3, 4, 5),
        token_traces=(),
        generated_tokens=3,
        stop_reason="done",
        steer_phase_token_spans=((0, 3),),
    )

    leaf = leaf_from_outcome(outcome=outcome, state=state)

    assert leaf.steer_phase_token_spans == ((0, 3),)


def test_leaf_event_payload_tracks_steer_phase_token_spans() -> None:
    """Leaf event payloads should serialize steer-phase spans for replay/inspection."""

    state = PathState(
        node_id="node_root",
        assistant_prefix="<think>",
        prompt_token_ids=(1, 2),
        token_ids=(),
        token_traces=(),
        branch_points_used=0,
    )
    outcome = DecodeOutcome(
        event_type="terminated",
        trigger_type=None,
        assistant_prefix="<think><steer>Plan</steer></think>",
        prompt_token_ids=(1, 2, 3, 4, 5),
        token_ids=(3, 4, 5),
        token_traces=(),
        generated_tokens=3,
        stop_reason="done",
        steer_phase_token_spans=((0, 3),),
    )
    leaf = leaf_from_outcome(outcome=outcome, state=state)

    payload = leaf_event_payload(leaf=leaf)

    assert payload["steer_phase_token_spans"] == [[0, 3]]


def test_append_steer_phase_span_keeps_accumulated_path_spans() -> None:
    """Fresh trigger outcomes should not erase earlier steer-phase spans."""

    base = DecodeOutcome(
        event_type="trigger",
        trigger_type="steer_boundary",
        assistant_prefix="<think><exec>Work</exec>",
        prompt_token_ids=(1, 2),
        token_ids=(3, 4, 5),
        token_traces=(),
        generated_tokens=3,
        stop_reason="",
    )
    continued = DecodeOutcome(
        event_type="continued",
        trigger_type=None,
        assistant_prefix="<think><exec>Work</exec><steer>Plan</steer>",
        prompt_token_ids=(1, 2, 3, 4, 5, 6, 7),
        token_ids=(3, 4, 5, 6, 7),
        token_traces=(),
        generated_tokens=5,
        stop_reason="",
    )

    updated = _append_steer_phase_span(
        accumulated_spans=((0, 2),),
        base=base,
        continued=continued,
    )

    assert updated.steer_phase_token_spans == ((0, 2), (3, 5))


def test_append_steer_phase_span_preserves_existing_spans_without_delta() -> None:
    """Malformed zero-token steer outcomes should keep path spans for the leaf."""

    base = DecodeOutcome(
        event_type="trigger",
        trigger_type="steer_boundary",
        assistant_prefix="<think>",
        prompt_token_ids=(1, 2),
        token_ids=(3, 4),
        token_traces=(),
        generated_tokens=2,
        stop_reason="",
    )
    continued = DecodeOutcome(
        event_type="terminated",
        trigger_type=None,
        assistant_prefix="<think>",
        prompt_token_ids=(1, 2),
        token_ids=(3, 4),
        token_traces=(),
        generated_tokens=2,
        stop_reason="missing_steer_or_think_close",
    )

    updated = _append_steer_phase_span(
        accumulated_spans=((0, 2),),
        base=base,
        continued=continued,
    )

    assert updated.steer_phase_token_spans == ((0, 2),)
